args.sparql:
SELECT ?attendance
WHERE {
  ?series wdt:P31 wd:Q566706 ;
          wdt:P662 wd:Q165265 ;
          wdt:P585 ?date.
  FILTER (year(?date) <= 2018)
  ?series wdt:P361 ?game .
  ?game wdt:P1718 1 .
  ?game wdt:P1096 ?attendance .
}
ORDER BY DESC(?attendance)
LIMIT 1
OFFSET 1

